DROP PROCEDURE IF EXISTS SCAH.UpsertUser
GO

CREATE PROCEDURE SCAH.UpsertUser
(
    @Email NVARCHAR(255),
    @UserGuid NVARCHAR(255),
    @LoginName NVARCHAR(255),
    @FirstName NVARCHAR(100) = '',
    @LastName NVARCHAR(255) = '',
    @Name NVARCHAR(255) = ''
)
AS
BEGIN
    SET NOCOUNT ON;

    IF EXISTS(SELECT 1 FROM SCAH.SCUSER WHERE Email = @Email)
    BEGIN
        UPDATE SCAH.SCUSER
        SET UserGuid = @UserGuid
        WHERE Email = @Email;
    END
    ELSE
    BEGIN
		DECLARE @NewUser TABLE (UserId INT);
        INSERT INTO SCAH.SCUSER
        (
            LOGINNAME, USERGUID, NAME, CREATEID, CREATEDATE,
            FIRSTNAME, LASTNAME, EMAIL, PASSWORDCHANGED, STATUS,
            ISLOGINENABLED, ISEXTERNAL, ISACTIVATED, ISEEM
        )
		OUTPUT INSERTED.SCUSERID INTO @NewUser
        VALUES
        (
            @LoginName, @UserGuid, @Name, 1, GETDATE(),
            @FirstName, @LastName, @Email, 0, 0,
            1, 0, 1, 0
        );
		DECLARE @UserId INT;
        SELECT @UserId = UserId FROM @NewUser;
		INSERT INTO SCAH.USERPREF(SCUSERID,[NAME], [VALUE], ISMODIFIED, MODIFYID,MODIFYDATE)
		VALUES (@UserId, 'ACTIVE_SCHEMANAME', 'FSH2', 0, 1, GETDATE())

		INSERT INTO SCAH.USERROLE(USERID,ROLEID,CREATEID,CREATEDATE,MODIFYID,MODIFYDATE,ISACTIVE)
		VALUES (@UserId, 1001, 1,GETDATE(), 1, GETDATE(), 1)
    END
END;
GO



